import{_ as o,o as t,c as n,ag as r}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"Device Model","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/20_structure/60_device_model.md","filePath":"10_core/20_structure/60_device_model.md"}'),i={name:"10_core/20_structure/60_device_model.md"};function a(s,e,l,c,d,g){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="device-model" tabindex="-1">Device Model <a class="header-anchor" href="#device-model" aria-label="Permalink to &quot;Device Model&quot;">​</a></h1><p>Rather than architecting everything around a singular developer or operator machine, the system uses a scalable, fleet-managed node structure with cloud orchestration.</p><h2 id="fleet-model-components" tabindex="-1">Fleet Model Components <a class="header-anchor" href="#fleet-model-components" aria-label="Permalink to &quot;Fleet Model Components&quot;">​</a></h2><ul><li><strong>QiLabs</strong>: The canonical local workstation root (<code>C:/QiLabs/</code>) on physical devices.</li><li><strong>Device Node</strong>: An enrolled machine in the fleet.</li><li><strong>Local Agent</strong>: The installed thin control service, reporting health and executing assigned jobs locally.</li><li><strong>Local Runtime</strong>: The machine-local execution layer for OCR, extraction, file chunking, and vectors.</li><li><strong>Watch Assignment</strong>: A configuration assigned from the hosted admin instructing a particular node to monitor specific directories or pipelines.</li><li><strong>Drop Zone</strong>: Specified ingress pathways (e.g. specialized folders) defined and assigned by the hosted admin.</li><li><strong>Primary Dev Node</strong>: A device node designated specifically for primary operator deployment, configuration, and structural adjustments.</li><li><strong>Ingest Edge Node</strong>: A specialized device node strictly responsible for watching paths/drop zones, reading local files, and ingesting them into the archive pipeline without administrative overhead.</li><li><strong>Infrastructure Node</strong>: A user-controlled server (e.g., <code>infra.backup_server</code>) providing local AI runtimes, secondary data services, and public application hosting under governed control.</li><li><strong>Fleet Control Plane</strong>: The hosted Admin platform authorizing and orchestrating action across the fleet of device nodes.</li><li><strong>Trust/Auth Boundary</strong>: Access control and credentials managed securely separating local worker execution from cross-tenant operations.</li></ul>',4)])])}const p=o(i,[["render",a]]);export{u as __pageData,p as default};
